param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId)
$ErrorActionPreference='Stop';$target='time_rules';$policy='nora.metaeditor_cli_success_v1';$editor='C:\Program Files\Darwinex MetaTrader 5\MetaEditor64.exe';$build='5.0.0.5836';$runtime='NoraPhase2TimeRuleRuntimeV1.mqh';$tester='NoraPhase2TimeRuleTesterCanaryV1.mq5';$ex5='NoraPhase2TimeRuleTesterCanaryV1.ex5';$root=Join-Path $env:USERPROFILE 'NoraPhase2TimeRuleValidation\compile-v1';$run=Join-Path $root $RunId;$evidence=Join-Path $run 'evidence'
function Hash($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()}
if(Test-Path $run){throw 'occupied compile destination'};New-Item -ItemType Directory $evidence -Force|Out-Null
try{$input=Get-Content (Join-Path $IncomingRoot 'time_rule_compile_input_v1.json') -Raw|ConvertFrom-Json;if($input.target_identifier-ne$target-or$input.compiler_policy-ne$policy){throw 'wrong target'};$r=Join-Path $IncomingRoot $runtime;$t=Join-Path $IncomingRoot $tester;if((Hash $r)-ne$input.runtime_sha256-or(Hash $t)-ne$input.tester_sha256){throw 'source hash'};if((Get-Item $editor).VersionInfo.FileVersion-ne$build){throw 'build'};$work=Join-Path $run 'compile';New-Item -ItemType Directory $work|Out-Null;Copy-Item $r $work;Copy-Item $t $work;$out=Join-Path $work $ex5;if(Test-Path $out){Remove-Item $out -Force};$log=Join-Path $work 'compile.log';$start=(Get-Date).ToUniversalTime();$args=@('/compile:"'+(Join-Path $work $tester)+'"','/log:"'+$log+'"');$p=Start-Process $editor -ArgumentList $args -PassThru;if(!$p.WaitForExit(120000)){$p.Kill();throw 'timeout'};$end=(Get-Date).ToUniversalTime();$line=@(Get-Content $log|?{$_-match '^Result:'})|select -Last 1;if(!$line-or$line-notmatch 'Result:\s*(\d+) errors,\s*(\d+) warnings'-or[int]$matches[1]-ne 0-or[int]$matches[2]-ne 0){throw 'diagnostics'};if(!(Test-Path $out)-or(Get-Item $out).LastWriteTimeUtc-lt$start){throw 'stale ex5'};$decision=if($p.ExitCode-eq 0){'accepted_zero'}elseif($p.ExitCode-eq 1){'accepted_metaeditor_5836_one'}else{throw 'exit'};Copy-Item $log $evidence;Copy-Item $out $evidence;$record=[ordered]@{schema_version='nora.time_rule_compiler_output_v1';target_identifier=$target;target_descriptor_identity=$input.target_descriptor_identity;compile_input_identity=$input.compile_input_identity;runtime_sha256=Hash $r;tester_sha256=Hash $t;package_identity=$input.package_identity;metaeditor_executable=$editor;observed_metaeditor_build=$build;exact_command=($editor+' '+($args-join' '));invocation_start_utc=$start.ToString('o');invocation_completion_utc=$end.ToString('o');raw_process_exit=$p.ExitCode;normalized_result='success';compiler_policy=$policy;policy_decision=$decision;log_path='compile.log';log_size=(Get-Item (Join-Path $evidence 'compile.log')).Length;log_sha256=Hash (Join-Path $evidence 'compile.log');warning_count=0;warnings=@();error_count=0;errors=@();ex5_path=$ex5;ex5_size=(Get-Item (Join-Path $evidence $ex5)).Length;ex5_modification_utc=(Get-Item (Join-Path $evidence $ex5)).LastWriteTimeUtc.ToString('o');ex5_sha256=Hash (Join-Path $evidence $ex5);stale_ex5_disposition='preexisting_target_removed_or_absent';freshness_proof=@{preexisting_ex5_removed_or_isolated=$true;produced_after_invocation_start=$true;single_unambiguous_ex5=$true};completion_state='completed';failure_reason=$null};$record|ConvertTo-Json -Depth 8|Set-Content (Join-Path $evidence 'compiler_record.json') -Encoding utf8;@{schema_version='nora.time_rule_compile_evidence_manifest_v1';target_identifier=$target;target_descriptor_identity=$input.target_descriptor_identity;compile_input_identity=$input.compile_input_identity}|ConvertTo-Json|Set-Content (Join-Path $evidence 'compile_evidence_manifest.json') -Encoding utf8;$inventory=@();foreach($x in @(@('compiler_record.json','compiler_record'),@('compile.log','compiler_log'),@($ex5,'ex5'),@('compile_evidence_manifest.json','compile_evidence_manifest'))){$f=Join-Path $evidence $x[0];$inventory+=@{path=$x[0];role=$x[1];sha256=Hash $f;size=(Get-Item $f).Length}};$inventory|ConvertTo-Json|Set-Content (Join-Path $evidence 'inventory.json') -Encoding utf8;Write-Output $evidence}catch{Remove-Item $run -Recurse -Force -ErrorAction SilentlyContinue;throw}
